            // Legacy: only rotation provided - preserve existing translate
            var currentTransform = el.style.transform || '';
            
            var transformFunctions = [];
            var regex = /(w+)(([^)]+))/g;
            var match;
            
            while ((match = regex.exec(currentTransform)) !== null) {
              var funcName = match[1];
              var funcValue = match[2];
              // Skip rotate functions, we'll add the new one
              if (funcName !== 'rotate') {
                transformFunctions.push(funcName + '(' + funcValue + ')');
              }
            }
            
            var newRotation = '';
